{
  "summary": "The paper proposes vote-k, an unsupervised graph-based selective annotation method combined with similarity-based prompt retrieval to reduce annotation costs for few-shot in-context learning with large language models. Extensive experiments on diverse NLP tasks demonstrate that vote-k significantly improves performance and stability over random and other baselines, achieving comparable or better results than finetuning with substantially less annotation.",
  "strengths": [
    {
      "point": "Addresses annotation cost explicitly for in-context learning",
      "evidence": "Proposes a two-step framework of selective annotation followed by prompt retrieval to reduce manual annotation while maintaining performance."
    },
    {
      "point": "Novel unsupervised graph-based selective annotation method",
      "evidence": "vote-k jointly optimizes diversity and representativeness using k-NN graphs and confidence bucket sampling, outperforming baselines like facility location and least-confidence sampling."
    },
    {
      "point": "Comprehensive empirical validation",
      "evidence": "Evaluated on 10 diverse NLP datasets with various tasks, showing consistent gains, robustness to domain shifts, and benefits across model sizes."
    },
    {
      "point": "Demonstrates significant annotation cost reduction compared to finetuning",
      "evidence": "Achieves similar or better performance than finetuning with 10-100× less annotation cost."
    },
    {
      "point": "Improves stability and reduces variance in in-context learning",
      "evidence": "vote-k reduces variance under different unlabeled data subsampling and domain shifts."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited novelty discussion and comparison to recent active learning methods",
      "evidence": "Does not sufficiently cite or compare to recent works on active learning or core-set selection for few-shot prompting beyond least-confidence sampling."
    },
    {
      "point": "Insufficient ablation and justification of hyperparameters",
      "evidence": "Parameters k=150 and ρ=10 are stated effective but lack detailed sensitivity analysis or robustness checks across datasets."
    },
    {
      "point": "Heavy reliance on Sentence-BERT embeddings without discussing limitations",
      "evidence": "No analysis on how well these embeddings capture task-relevant similarity for diverse tasks or potential biases introduced."
    },
    {
      "point": "Baselines for selective annotation are limited",
      "evidence": "Does not compare against more recent or sophisticated active learning or core-set selection methods that could be stronger competitors."
    },
    {
      "point": "Finetuning comparison details are sparse",
      "evidence": "Unclear if finetuning baselines are fully optimized or use comparable model sizes and training budgets, possibly biasing results."
    },
    {
      "point": "Lacks analysis of annotation time, human effort, or cost beyond example counts",
      "evidence": "Evaluation focuses mainly on accuracy or task-specific metrics without practical annotation efficiency measures."
    },
    {
      "point": "Reproducibility concerns due to missing annotation and computational details",
      "evidence": "No information on annotation process, quality control, graph construction runtime, or hardware used."
    },
    {
      "point": "Clarity issues in explaining confidence bucket sampling and integration with prompt retrieval",
      "evidence": "Descriptions are brief and lack motivation or illustration, making it hard to understand or reproduce."
    },
    {
      "point": "No discussion on scalability to very large unlabeled pools",
      "evidence": "Building k-NN graphs over entire unlabeled sets may be computationally prohibitive, but this is not addressed."
    },
    {
      "point": "Limited exploration of generalizability beyond NLP and domain shift depth",
      "evidence": "Experiments only on NLP tasks; domain shift scenarios and results lack detailed breakdown."
    },
    {
      "point": "Sparse details on code release completeness and instructions",
      "evidence": "Only an anonymized link mentioned without further information, potentially hindering adoption."
    }
  ],
  "questions": [
    {
      "question": "How sensitive is vote-k to the choice of hyperparameters k and ρ across different datasets and domains?",
      "motivation": "Understanding robustness is critical for practical adoption and tuning effort."
    },
    {
      "question": "How does vote-k perform compared to more recent or advanced active learning and core-set selection methods?",
      "motivation": "To validate the claimed novelty and effectiveness relative to the state of the art."
    },
    {
      "question": "What are the annotation protocols and quality control measures used for the selected examples?",
      "motivation": "Essential for reproducibility and assessing the true annotation cost and quality."
    },
    {
      "question": "Can the method scale efficiently to very large unlabeled pools, and are there approximations to reduce computational cost?",
      "motivation": "Scalability is important for real-world applications with massive unlabeled data."
    },
    {
      "question": "How well does the approach generalize to non-NLP tasks or modalities where embedding quality may vary?",
      "motivation": "To assess broader applicability beyond the tested NLP datasets."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
